      T.ok('clean export → nocturnal_hypo NOT stamped (no clamp)', !(expC.ganglior_events[0].meta && expC.ganglior_events[0].meta.clampFloor));
      // Integrator adaptGlucoDex: surfaces the clamp + down-weights the clip-floor hypos.
