      var fakeProv = { buildHash: 'abc123def456', generated: '2026-06-21T23:00:00Z', inputs: [{ name: 'Verity RR 2026-06-21.txt', sha256: 'deadbeef', bytes: 4242 }] };
      var envP = JSON.parse(JSON.stringify(pristine));
